 public function validateApproval($r):void{if(($r['schema_version']??null)!==$this->config['portfolio_approval_schema_version'])throw new \InvalidArgumentException('bad approval schema');if(($r['approval_result']['production_approved']??null)!==false||($r['approval_result']['execution_approved']??null)!==false||($r['approved_action']??null)!==null||($r['approved_quantity']??null)!==null||($r['approved_order']??null)!==null)throw new \InvalidArgumentException('approval must be non executable');if(($r['status']??null)==='approved_reference'&&(($r['authorization_validation']['status']??null)!=='valid_reference_authorization'||($r['approval_basis']['portfolio_limits_passed']??null)!==true))throw new \InvalidArgumentException('approved reference invariant failed');if(count($r['reason_codes'])!==count(array_unique($r['reason_codes'])))throw new \InvalidArgumentException('duplicate approval reasons');}
